package main

import (
	"fmt"
	"sync"
)

func reshelf(section string, wg *sync.WaitGroup) {
	defer wg.Done()
	fmt.Printf("Section %s reshelved\n", section)
}

func main() {
	var wg sync.WaitGroup

	for _, s := range []string{"A", "B", "C"} {
		wg.Add(1)
		go reshelf(s, &wg)
	}

	wg.Wait()
	fmt.Println("All sections complete — library ready")
}

package main

import "fmt"

func catalogSearch(ch chan string) {
	titles := []string{"Dune", "Neuromancer", "Snow Crash", "Hyperion", "Foundation"}
	for _, t := range titles {
		ch <- t
	}
	close(ch)
}

func main() {
	ch := make(chan string)
	go catalogSearch(ch)

	for title := range ch {
		fmt.Println("Found:", title)
	}
	fmt.Println("Catalog search complete")
}

package main

import (
	"fmt"
	"sync"
)

type LibraryCounter struct {
	mu    sync.Mutex
	count int
}

func (c *LibraryCounter) CheckOut() {
	c.mu.Lock()
	defer c.mu.Unlock()
	c.count++
}

func (c *LibraryCounter) Total() int {
	c.mu.Lock()
	defer c.mu.Unlock()
	return c.count
}

func main() {
	counter := &LibraryCounter{}
	var wg sync.WaitGroup

	for i := 0; i < 100; i++ {
		wg.Add(1)
		go func() {
			defer wg.Done()
			counter.CheckOut()
		}()
	}

	wg.Wait()
	fmt.Println("Total check-outs:", counter.Total())
}

